                <p class="text-xs text-stone-500">Lütfen bekleyin</p>
            </div>
        </div>

        <div id="auth-container" class="absolute inset-0 z-40 theme-bg-phone flex flex-col px-6 pt-12 pb-6 overflow-y-auto transition-all duration-300">
