                        <i data-lucide="users" class="absolute left-3.5 w-4 h-4 theme-text-muted"></i>
                        <input type="text" id="reg-sinif" class="w-full pl-10 pr-4 py-2.5 rounded-xl border theme-border theme-card-bg theme-text-main text-xs focus:ring-2 focus:ring-[var(--theme-primary)] focus:outline-none transition-all" placeholder="Örn: Osmanlıca Başlangıç Grubu">
                    </div>
