        </div>

        <!-- ================= UYGULAMA ANA İÇERİĞİ (GİRİŞ YAPINCA GÖSTERİLECEK) ================= -->
        <div id="main-application-flow" class="lisani-main-flow hidden flex-1 flex flex-col overflow-hidden animate-fade-in h-full min-h-0 relative z-10">
            
            <!-- ANA EKRAN İÇERİK ALANI (KAYDIRILABİLİR ALAN) -->
            <div class="lisani-screens flex-1 overflow-y-auto overflow-x-hidden px-4 sm:px-5 pt-4 sm:pt-6 pb-6 sm:pb-8 transition-colors duration-300 touch-pan-y min-h-0" id="screens-container">

                <!-- 1. SEKME: GELİŞİM (TEST ANALİZLERİ SÜRÜMÜ) -->
                <div id="screen-ai" class="screen flex-col space-y-4">
                    <div class="flex items-center space-x-3 pb-3 border-b theme-border transition-colors">
                        <div class="w-10 h-10 rounded-full theme-light-bg flex items-center justify-center theme-primary-color transition-colors shadow-inner">
