                                </div>
                                <span class="text-[10px] theme-primary-color font-extrabold flex items-center space-x-1.5 bg-stone-950/40 px-2.5 py-1 rounded-full border theme-border">
                                    <span class="w-2 h-2 rounded-full bg-emerald-500 inline-block animate-pulse"></span>
                                    <span id="ai-chart-badge-label">Skorlarım</span>
                                </span>
                            </div>
                            
                            <!-- SVG Alanı -->
                            <div class="relative w-full h-60 bg-black/45 rounded-2xl p-2 border theme-border flex items-center justify-center shadow-inner">
                                <svg id="progress-svg-chart" class="w-full h-full" viewBox="0 0 500 260">
                                    <defs>
                                        <linearGradient id="chart-area-grad" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="0%" stop-color="var(--theme-primary)" stop-opacity="0.4" />
                                            <stop offset="100%" stop-color="var(--theme-primary)" stop-opacity="0.0" />
                                        </linearGradient>
                                    </defs>
                                </svg>
                            </div>
                        </div>

                        <!-- SEÇİLEN SINAVIN DETAYLI ANALİZ KARTI (Modern Glass) -->
                        <div id="selected-trial-detail-card" class="lisani-glass-panel rounded-2xl p-4 space-y-3 transition-all hidden">
                            <div class="flex justify-between items-center pb-2 border-b theme-border">
                                <span class="text-xs font-bold theme-text-main flex items-center space-x-1.5">
                                    <i data-lucide="bar-chart-2" class="w-4 h-4 theme-primary-color"></i>
                                    <span id="detail-trial-title" class="font-extrabold">Seviye 1 - Test 1 Sonucu</span>
                                </span>
                                <span class="text-[10px] theme-text-muted font-bold" id="detail-trial-date">01.06.2026</span>
                            </div>
                            
                            <div class="grid grid-cols-2 gap-2.5 text-xs">
                                <div class="p-3 theme-light-bg rounded-xl border theme-border flex flex-col justify-between">
                                    <span class="text-[9px] theme-text-muted font-bold uppercase tracking-wider">Doğru Sayısı</span>
                                    <span class="text-xs font-black text-emerald-450 mt-0.5" id="detail-trial-corrects">4 Doğru</span>
                                </div>
                                <div class="p-3 theme-light-bg rounded-xl border theme-border flex flex-col justify-between">
